import{_ as s,o as a,c as n,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Repositorios servicios y eventos","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/04-repositorios-servicios-y-eventos.md","filePath":"full-stack/arquitectura/ddd/04-repositorios-servicios-y-eventos.md","lastUpdated":1782521464000}'),o={name:"full-stack/arquitectura/ddd/04-repositorios-servicios-y-eventos.md"};function t(p,e,r,l,c,d){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="repositorios-servicios-y-eventos" tabindex="-1">Repositorios servicios y eventos <a class="header-anchor" href="#repositorios-servicios-y-eventos" aria-label="Permalink to &quot;Repositorios servicios y eventos&quot;">​</a></h1><p>Estos patrones ayudan a conectar el modelo de dominio con persistencia, operaciones que no pertenecen a una sola entidad y comunicacion con otros procesos.</p><h2 id="repositorios" tabindex="-1">Repositorios <a class="header-anchor" href="#repositorios" aria-label="Permalink to &quot;Repositorios&quot;">​</a></h2><p>Un repositorio representa una coleccion de agregados.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OrderRepository</span></span>
<span class="line"><span>  findById(orderId)</span></span>
<span class="line"><span>  save(order)</span></span></code></pre></div><p>No deberia exponer detalles de SQL, ORM o indices. Su lenguaje debe ser del dominio.</p><h2 id="repositorios-no-son-daos-genericos" tabindex="-1">Repositorios no son DAOs genericos <a class="header-anchor" href="#repositorios-no-son-daos-genericos" aria-label="Permalink to &quot;Repositorios no son DAOs genericos&quot;">​</a></h2><p>Evita:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>findAll()</span></span>
<span class="line"><span>findByAnyField()</span></span>
<span class="line"><span>updatePartial(data)</span></span></code></pre></div><p>Prefiere operaciones necesarias para casos de uso reales:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>findPendingPayment(orderId)</span></span>
<span class="line"><span>findConfirmedOrdersForCustomer(customerId)</span></span></code></pre></div><h2 id="servicios-de-dominio" tabindex="-1">Servicios de dominio <a class="header-anchor" href="#servicios-de-dominio" aria-label="Permalink to &quot;Servicios de dominio&quot;">​</a></h2><p>Un servicio de dominio contiene una regla que no encaja naturalmente en una entidad o value object.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PricingPolicy.calculatePrice(course, student, coupon)</span></span></code></pre></div><p>No debe convertirse en un cajon para cualquier logica. Si una regla pertenece a una entidad, dejala ahi.</p><h2 id="servicios-de-aplicacion" tabindex="-1">Servicios de aplicacion <a class="header-anchor" href="#servicios-de-aplicacion" aria-label="Permalink to &quot;Servicios de aplicacion&quot;">​</a></h2><p>Orquestan casos de uso:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ConfirmOrderUseCase</span></span>
<span class="line"><span>  load order</span></span>
<span class="line"><span>  call order.confirm()</span></span>
<span class="line"><span>  save order</span></span>
<span class="line"><span>  publish events</span></span></code></pre></div><p>No son lo mismo que servicios de dominio.</p><h2 id="eventos-de-dominio" tabindex="-1">Eventos de dominio <a class="header-anchor" href="#eventos-de-dominio" aria-label="Permalink to &quot;Eventos de dominio&quot;">​</a></h2><p>Representan algo relevante que ya ocurrio:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OrderConfirmed</span></span>
<span class="line"><span>InvoicePaid</span></span>
<span class="line"><span>CoursePublished</span></span>
<span class="line"><span>UserRegistered</span></span></code></pre></div><p>Sirven para desacoplar reacciones:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OrderConfirmed</span></span>
<span class="line"><span>  -&gt; send email</span></span>
<span class="line"><span>  -&gt; update analytics</span></span>
<span class="line"><span>  -&gt; reserve stock</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Los repositorios trabajan con agregados.</li><li>Los servicios de dominio expresan reglas reales.</li><li>Los casos de uso orquestan, no esconden reglas.</li><li>Los eventos se nombran en pasado.</li><li>Los eventos no sustituyen invariantes que deben cumplirse en la transaccion.</li></ul>`,27)])])}const v=s(o,[["render",t]]);export{h as __pageData,v as default};
